function Footer({ connected }) {
    return (
        <footer style={{ marginTop: '24px', padding: '16px', background: '#1f2937', borderRadius: '12px', color: '#e5e7eb' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', flexWrap: 'wrap', alignItems: 'center' }}>
                <div>
                    <h3>Logistics Dashboard</h3>
                    <p>Hyderabad dispatch center | Live order monitoring</p>
                </div>
                <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                    <span style={{ display: 'flex', alignItems: 'center', gap: '6px', fontSize: '0.9rem' }}>
                        <span style={{ width: 10, height: 10, borderRadius: '50%', background: connected ? '#22c55e' : '#ef4444', display: 'inline-block' }}></span>
                        System Status: {connected ? 'Online' : 'Offline'}
                    </span>
                    <a style={{ color: '#9ca3af', textDecoration: 'none' }} href="#">Instagram</a>
                    <a style={{ color: '#9ca3af', textDecoration: 'none' }} href="#">Twitter</a>
                    <a style={{ color: '#9ca3af', textDecoration: 'none' }} href="#">LinkedIn</a>
                </div>
            </div>
            <p style={{ marginTop: '10px', fontSize: '0.8rem' }}>© 2026 Hyderabad Smart Logistics</p>
        </footer>
    );
}

export default Footer;
